// Check if this email is from a known HOO lead
const fs = require('fs');
const path = require('path');
const LEADS_DIR = 'C:\\Users\\Matth\\hoo-workspace\\engine\\leads';

const senderEmail = $json.from?.toLowerCase() || '';
const subject = $json.subject || '';
const snippet = $json.snippet || '';

// Load all lead JSONs
let matchedLead = null;
try {
  const files = fs.readdirSync(LEADS_DIR).filter(f => f.endsWith('.json'));
  for (const file of files) {
    const lead = JSON.parse(fs.readFileSync(path.join(LEADS_DIR, file)));
    if (lead.email && lead.email.toLowerCase() === senderEmail) {
      matchedLead = lead;
      matchedLead.filename = file;
      break;
    }
  }
} catch(e) { console.error(e); }

return [{
  json: {
    matched: !!matchedLead,
    lead: matchedLead,
    sender: senderEmail,
    subject,
    snippet,
    timestamp: new Date().toISOString()
  }
}];

// Update lead stage to 'responded' and log reply
const fs = require('fs');
const path = require('path');
const LEADS_DIR = 'C:\\Users\\Matth\\hoo-workspace\\engine\\leads';

const lead = $json.lead;
const file = path.join(LEADS_DIR, lead.filename);

if (fs.existsSync(file)) {
  const data = JSON.parse(fs.readFileSync(file));
  data.stage = 'responded';
  data.responded_date = new Date().toISOString().split('T')[0];
  data.reply_snippet = $json.snippet;
  data.reply_subject = $json.subject;
  fs.writeFileSync(file, JSON.stringify(data, null, 2));
}

return [{ json: { updated: true, lead: lead.business, stage: 'responded' } }];

